mapper.select:
SELECT tag_id
  FROM SCOTT.tags
 WHERE tag_text = #{tagText, jdbcType=VARCHAR}

SELECT p.post_id AS postId,
       p.content  AS content
  FROM SCOTT.posts p
 WHERE p.post_id   = #{postId, jdbcType=NUMERIC}
   AND p.account_id = #{accountId, jdbcType=NUMERIC}

mapper.update:
UPDATE SCOTT.posts
   SET content = #{content, jdbcType=VARCHAR}
 WHERE post_id = #{postId, jdbcType=NUMERIC}
   AND account_id = #{accountId, jdbcType=NUMERIC}

mapper.delete:
DELETE FROM SCOTT.posts
 WHERE post_id = #{postId, jdbcType=NUMERIC}
   AND account_id = #{accountId, jdbcType=NUMERIC}

